import{_ as l,o as i,c as e,a2 as n}from"./chunks/framework.Do_4EYrn.js";const c=JSON.parse('{"title":"第 26 章 按任务责任选择 WorkBuddy 用法","description":"本章不复刻真实组织架构，而是按一个人在任务中承担的责任选择 WorkBuddy 用法。同一个人可能同时承担起草、复核和跟踪等不同角色。 同一项虚构的“办公设备盘点”任务中，经办人负责材料清单和数据核对，会议组织者负责确认待办，复核人负责检查口径和共享范围。三者选择的章节不同，但都不能根据角色名称自动扩大权限。","frontmatter":{},"headers":[],"relativePath":"bluebook/第四篇 岗位与行业落地/第 26 章 岗位路线图：不同岗位如何把 WorkBuddy 用深/index.md","filePath":"bluebook/第四篇 岗位与行业落地/第 26 章 岗位路线图：不同岗位如何把 WorkBuddy 用深/index.md","lastUpdated":1784100816000}'),s={name:"bluebook/第四篇 岗位与行业落地/第 26 章 岗位路线图：不同岗位如何把 WorkBuddy 用深/index.md"};function t(r,a,o,d,p,h){return i(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="第-26-章-按任务责任选择-workbuddy-用法" tabindex="-1">第 26 章 按任务责任选择 WorkBuddy 用法 <a class="header-anchor" href="#第-26-章-按任务责任选择-workbuddy-用法" aria-label="Permalink to &quot;第 26 章 按任务责任选择 WorkBuddy 用法&quot;">​</a></h1><p>本章不复刻真实组织架构，而是按一个人在任务中承担的责任选择 WorkBuddy 用法。同一个人可能同时承担起草、复核和跟踪等不同角色。</p><h2 id="材料起草" tabindex="-1">材料起草 <a class="header-anchor" href="#材料起草" aria-label="Permalink to &quot;材料起草&quot;">​</a></h2><ul><li>从第14章开始，把需求变成任务卡。</li><li>使用第11章完成 Word、Excel、PPT 交付。</li><li>涉及正式公文时使用第18章，并保留依据和待确认问题。</li><li>重点检查：事实来源、模板、版本和读者。</li></ul><h2 id="复核审批" tabindex="-1">复核审批 <a class="header-anchor" href="#复核审批" aria-label="Permalink to &quot;复核审批&quot;">​</a></h2><ul><li>要求输出修改说明、事实清单和风险清单，不只看终稿。</li><li>使用第20章核对引用来源和版本。</li><li>对外发、审批和结论设置明确人工确认点。</li><li>重点检查：权限、依据、例外和责任边界。</li></ul><h2 id="会议组织" tabindex="-1">会议组织 <a class="header-anchor" href="#会议组织" aria-label="Permalink to &quot;会议组织&quot;">​</a></h2><ul><li>会前用任务卡整理议题和待决问题。</li><li>会后使用第19章形成纪要草稿和待办台账。</li><li>重点检查：结论、责任、时限、验收和共享范围。</li></ul><h2 id="数据分析" tabindex="-1">数据分析 <a class="header-anchor" href="#数据分析" aria-label="Permalink to &quot;数据分析&quot;">​</a></h2><ul><li>使用第17章完成质量检查、口径确认、汇总和图表。</li><li>结论必须绑定证据，低样本和缺失值必须提示。</li><li>重点检查：口径、隐私、因果边界和可复算性。</li></ul><h2 id="项目经办" tabindex="-1">项目经办 <a class="header-anchor" href="#项目经办" aria-label="Permalink to &quot;项目经办&quot;">​</a></h2><ul><li>使用第12章治理资料与版本。</li><li>使用第21章建立资料目录、事实表、证据矩阵和问题清单。</li><li>重点检查：材料完整性、专业复核和决策边界。</li></ul><h2 id="知识维护" tabindex="-1">知识维护 <a class="header-anchor" href="#知识维护" aria-label="Permalink to &quot;知识维护&quot;">​</a></h2><ul><li>使用第16章建立来源页、知识卡和主题入口。</li><li>使用第20章维护版本和引用关系。</li><li>重复稳定的方法可按第22章沉淀为 Skill。</li><li>重点检查：来源、状态、权限和更新时间。</li></ul><h2 id="合成示例" tabindex="-1">合成示例 <a class="header-anchor" href="#合成示例" aria-label="Permalink to &quot;合成示例&quot;">​</a></h2><p>同一项虚构的“办公设备盘点”任务中，经办人负责材料清单和数据核对，会议组织者负责确认待办，复核人负责检查口径和共享范围。三者选择的章节不同，但都不能根据角色名称自动扩大权限。</p><h3 id="可复制岗位任务卡" tabindex="-1">可复制岗位任务卡 <a class="header-anchor" href="#可复制岗位任务卡" aria-label="Permalink to &quot;可复制岗位任务卡&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我在本任务中的责任是：{起草/复核/会议组织/数据分析/项目经办/知识维护}</span></span>
<span class="line"><span>任务目标：{目标}</span></span>
<span class="line"><span>输入材料：{材料}</span></span>
<span class="line"><span>我有权决定：{范围}</span></span>
<span class="line"><span>需要他人确认：{事项}</span></span>
<span class="line"><span>输出物：{文件或记录}</span></span>
<span class="line"><span>验收标准：{标准}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请推荐应阅读的蓝皮书章节、执行顺序、人工确认点和最小样本。</span></span>
<span class="line"><span>不要根据角色名称推断我的权限或公司流程。</span></span></code></pre></div><h2 id="验收与边界" tabindex="-1">验收与边界 <a class="header-anchor" href="#验收与边界" aria-label="Permalink to &quot;验收与边界&quot;">​</a></h2><ul><li>路线按任务责任而不是部门名称选择。</li><li>AI 的建议不扩大个人已有权限。</li><li>每项路线都有明确输入、输出和人工确认点。</li><li>岗位职责、审批链条和组织关系以公司正式材料为准。</li></ul><h2 id="常见弯路" tabindex="-1">常见弯路 <a class="header-anchor" href="#常见弯路" aria-label="Permalink to &quot;常见弯路&quot;">​</a></h2><ul><li>按职位名称套用整套流程，会忽略本次任务的真实责任。</li><li>看到“复核”就默认拥有批准权限，可能造成越权。</li><li>一个人承担多个责任时省略交接记录，后续难以复盘。应分别记录起草、复核和确认状态。</li></ul>`,22)])])}const b=l(s,[["render",t]]);export{c as __pageData,b as default};
